class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        int n = nums.length;
        int m = nums[0].length();
        int[] answer = new int[queries.length];
        String[] trimmedNums = new String[n];

        for (int i = 0; i < queries.length; i++) {
            int k = queries[i][0];
            int trim = queries[i][1];
            for (int j = 0; j < n; j++) {
                trimmedNums[j] = nums[j].substring(m - trim);
            }
            Integer[] indices = new Integer[n];
            for (int j = 0; j < n; j++) {
                indices[j] = j;
            }
            Arrays.sort(indices, (a, b) -> {
                int cmp = trimmedNums[a].compareTo(trimmedNums[b]);
                return cmp == 0 ? a - b : cmp;
            });
            answer[i] = indices[k - 1];
        }
        return answer;
    }
}
